package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

/**
 * Unit spec for {@link MultiJoinPlan#sinkUnconsumedPatterns}: patterns whose exclusively produced slots no other child
 * consumes move to a trailing suffix (so the factorized tail split can claim them as branches), guarded so selective
 * patterns — the pipeline's early-pruning workhorses — stay put.
 */
public class LmdbNativeFactorizedSinkTest {

	/** A pattern binding subject slot {@code sSlot} and object slot {@code oSlot} (constant predicate). */
	private static PatternPlan pattern(int sSlot, int oSlot, double estimate) {
		Term object = oSlot < 0 ? Term.constant(999) : Term.slot(oSlot);
		return new PatternPlan(Term.slot(sSlot), Term.constant(7), object, Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, estimate);
	}

	@Test
	public void midPlanUnconsumedLegSinksBehindItsConsumers() {
		PatternPlan typeAnchor = pattern(0, -1, 10); // produces only the shared subject: never sinks
		PatternPlan leg = pattern(0, 1, 25); // exclusive ?l, nothing reads it
		PatternPlan chainLink = pattern(0, 2, 40); // ?x is consumed by chainEnd: never sinks
		PatternPlan chainEnd = pattern(2, 3, 20_000); // exclusive ?y

		SlotPlan[] ordered = { typeAnchor, leg, chainLink, chainEnd };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, new MaskedFilter[0]);

		assertThat(ordered).containsExactly(typeAnchor, chainLink, leg, chainEnd);
	}

	@Test
	public void selectiveLegStaysPutToKeepEarlyPruning() {
		PatternPlan anchor = pattern(0, -1, 10);
		PatternPlan needleLeg = pattern(0, 1, 3); // more selective than every non-candidate: prunes early
		PatternPlan chainLink = pattern(0, 2, 40);
		PatternPlan chainEnd = pattern(2, 3, 20_000);

		SlotPlan[] ordered = { anchor, needleLeg, chainLink, chainEnd };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, new MaskedFilter[0]);

		assertThat(ordered).containsExactly(anchor, needleLeg, chainLink, chainEnd);
	}

	@Test
	public void pureStarKeepsSmallestLegAsDriver() {
		PatternPlan big = pattern(0, 2, 5000);
		PatternPlan small = pattern(0, 1, 100);
		PatternPlan bigger = pattern(0, 3, 9000);

		SlotPlan[] ordered = { big, small, bigger };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, new MaskedFilter[0]);

		assertThat(ordered).containsExactly(small, big, bigger);
	}

	@Test
	public void seedBoundSlotsCountAsConsumed() {
		// slot 1 is bound by the seed (external binding): the leg's output is not exclusive, so the
		// pattern is a constraint on the seed value, not a sinkable fan-out
		PatternPlan anchor = pattern(0, -1, 10);
		PatternPlan seededLeg = pattern(0, 1, 500);
		PatternPlan chainLink = pattern(0, 2, 40);
		PatternPlan chainEnd = pattern(2, 3, 20_000);

		SlotPlan[] ordered = { anchor, seededLeg, chainLink, chainEnd };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 1L << 1, new MaskedFilter[0]);

		assertThat(ordered).containsExactly(anchor, seededLeg, chainLink, chainEnd);
	}

	@Test
	public void singleBranchFilterReadLegSinksWithItsFilter() {
		// The filter reads only this leg's exclusive slot, so the factorized split can attach it to that branch.
		PatternPlan typeAnchor = pattern(0, -1, 10);
		PatternPlan filteredLeg = pattern(0, 1, 25);
		PatternPlan chainLink = pattern(0, 2, 40);
		PatternPlan chainEnd = pattern(2, 3, 20_000);
		MaskedFilter[] filters = { new MaskedFilter(row -> true, 1L << 1) };

		SlotPlan[] ordered = { typeAnchor, filteredLeg, chainLink, chainEnd };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, filters);

		assertThat(ordered).containsExactly(typeAnchor, chainLink, filteredLeg, chainEnd);
	}

	@Test
	public void filterSpanningTwoProspectiveBranchesKeepsBothInPlace() {
		PatternPlan typeAnchor = pattern(0, -1, 10);
		PatternPlan firstLeg = pattern(0, 1, 25);
		PatternPlan chainLink = pattern(0, 2, 40);
		PatternPlan secondLeg = pattern(2, 3, 20_000);
		MaskedFilter[] filters = { new MaskedFilter(row -> true, (1L << 1) | (1L << 3)) };

		SlotPlan[] ordered = { typeAnchor, firstLeg, chainLink, secondLeg };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, filters);

		assertThat(ordered).containsExactly(typeAnchor, firstLeg, chainLink, secondLeg);
	}

	@Test
	public void unboundedEstimateDoesNotDisqualifyAnOtherwiseSinkableLeg() {
		PatternPlan typeAnchor = pattern(0, -1, 10);
		PatternPlan unboundedLeg = pattern(0, 1, Double.POSITIVE_INFINITY);
		PatternPlan chainLink = pattern(0, 2, 40);
		PatternPlan chainEnd = pattern(2, 3, 20_000);

		SlotPlan[] ordered = { typeAnchor, unboundedLeg, chainLink, chainEnd };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, new MaskedFilter[0]);

		assertThat(ordered).containsExactly(typeAnchor, chainLink, unboundedLeg, chainEnd);
	}

	@Test
	public void filteredFreshTailGroupKeepsTheCountOnlyGuard() {
		PatternPlan typeAnchor = pattern(0, -1, 10);
		PatternPlan filteredGroup = pattern(0, 1, 25);
		MaskedFilter[] filters = { new MaskedFilter(row -> true, 1L << 1) };
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { typeAnchor, filteredGroup }, filters);
		MultiJoinPlan.OrderedPlan derived = plan.derive(0L, true);

		assertThat(FactorizedTail.probe(derived, filters, 0L, new int[] { 1 },
				new AggregateSpec[] { AggregateSpec.star("count") }))
						.as("a re-placed filter on the fresh tail group cannot be represented by grouped pair bucketing")
						.isNull();
	}

	@Test
	public void disconnectedPatternNeverSinks() {
		// the cross-product pattern shares no slot with the rest: the optimizer's placement stands
		PatternPlan anchor = pattern(0, 1, 10);
		PatternPlan disconnected = pattern(4, 5, 5000);
		PatternPlan chainEnd = pattern(1, 2, 20_000);

		SlotPlan[] ordered = { anchor, disconnected, chainEnd };
		MultiJoinPlan.sinkUnconsumedPatterns(ordered, 0L, new MaskedFilter[0]);

		assertThat(ordered).containsExactly(anchor, disconnected, chainEnd);
	}
}
